mapper.select:
SELECT F.FAQ_NO AS faqNo , F.FAQ_TYPE_CD AS faqTypeCd , FT.FAQ_TYPE_NM AS faqTypeNm , F.FAQ_QUESTION AS faqQuestion , F.FAQ_ANSWER AS faqAnswer , TO_CHAR(F.CREATE_DT, 'YYYY-MM-DD') AS createDt FROM FAQ F JOIN FAQ_TYPE FT ON FT.FAQ_TYPE_CD = F.FAQ_TYPE_CD
WHERE F.FAQ_TYPE_CD = #{faqTypeCd}
ORDER BY FT.FAQ_TYPE_NM, F.CREATE_DT
